const results = [];
const today = new Date();

for (let i = 1; i <= 3; i++) {  // exclut le mois courant
    const date = new Date(today.getFullYear(), today.getMonth() - i, 1);

    const year = date.getFullYear();
    const month = String(date.getMonth() + 1).padStart(2, '0');

    const startDate = `${year}-${month}-01`;

    results.push({
        json: {
            startDate: startDate
        }
    });
}

return results;

const results = [];
const today = new Date();

for (let i = 1; i <= 3; i++) {  // exclut le mois courant

    // Premier jour du mois précédent
    const date = new Date(today.getFullYear(), today.getMonth() - i, 1);

    const year = date.getFullYear();
    const month = String(date.getMonth() + 1).padStart(2, '0');

    // Dernier jour du mois :
    // astuce : jour 0 du mois suivant = dernier jour du mois courant
    const lastDayDate = new Date(year, date.getMonth() + 1, 0);
    const lastDay = String(lastDayDate.getDate()).padStart(2, '0');

    const endDate = `${year}-${month}-${lastDay}`;

    results.push({
        json: {
            endDate: endDate
        }
    });
}

return results;

