const dataSetId = "qNTxFeMEaKj";   // ton dataset cible
const completeDate = null;        // ← maintenant null

const dataValues = [];
let globalOrgUnit = null;

for (const item of $input.all()) {

    const rows = item.json.rows || [];

    for (const row of rows) {

        const dataElement = row[0];
        const orgUnit = row[1];
        const period = row[2];
        const value = row[3];

        globalOrgUnit = orgUnit; 

        dataValues.push({
            dataElement,
            period,
            orgUnit,
            value
        });
    }
}

return [
  {
    json: {
      dataSet: dataSetId,
      completeDate: completeDate,
      orgUnit: globalOrgUnit,
      dataValues: dataValues
    }
  }
];

